// Puxa a capa da Newsletter
const newsletterData = $("Buscar Newsletter (Supabase)").first().json;
const newsletter = Array.isArray(newsletterData) ? newsletterData[0] : newsletterData;

// Puxa o array de Posts reais que acabamos de buscar
const postsData = $("Buscar Posts da Edição").first().json;
const posts = (Array.isArray(postsData) ? postsData[0].posts_array : postsData.posts_array) || [];

const world = (newsletter.world || "tech").toLowerCase();

// === CONFIGURAÇÃO DE TEMAS ===
const themes = {
  tech: {
    color: "#00FF41",
    bg: "#040804",
    cardBg: "#0a120a",
    emoji: "⚡",
    headerLabel: "TECH_HACKER",
    greeting: "Sintonizado na Frequência",
    footerSignOff: "Finalizando a compilação..."
  },
  game: {
    color: "#EAB308",
    bg: "#080600",
    cardBg: "#120e00",
    emoji: "🎮",
    headerLabel: "GAME_BUILDER",
    greeting: "Start Pressionado",
    footerSignOff: "Salvando progresso..."
  },
  music: {
    color: "#9D00FF",
    bg: "#040008",
    cardBg: "#0a0012",
    emoji: "🎵",
    headerLabel: "MUSIC_MAKER",
    greeting: "Sintonizado na Frequência",
    footerSignOff: "Desligando os amplificadores..."
  },
  gear: {
    color: "#EF4444",
    bg: "#080000",
    cardBg: "#120000",
    emoji: "⚙️",
    headerLabel: "GEAR_SETUP",
    greeting: "Motor Ligado",
    footerSignOff: "Cortando a ignição..."
  }
};

const theme = themes[world] || themes.tech;

// === MONTAGEM DINÂMICA DO SETLIST ===
let htmlPosts = "";
let whatsappPosts = "";

posts.forEach(post => {
  let wppSum = post.whatsapp_summary || post.title;
  whatsappPosts += `🟣 ${wppSum}\n`;

  htmlPosts += `
    <div style="margin-bottom: 24px;">
      <h3 style="color: ${theme.color}; font-size: 14px; font-weight: 800; letter-spacing: 1px; margin: 0 0 8px;">
        ${(post.sub_category || "").toUpperCase()}
      </h3>
      <h2 style="color: #ffffff; font-size: 20px; font-weight: bold; margin: 0 0 12px; line-height: 1.3;">
        ${post.title}
      </h2>
      <p style="color: #a0a0a0; font-size: 15px; line-height: 1.6; margin: 0 0 16px;">
        ${post.summary}
      </p>
      <a href="${post.url}" style="color: ${theme.color}; text-decoration: none; font-size: 14px; font-weight: bold;">
        Ler fonte original →
      </a>
    </div>
  `;
});

// === MONTAGEM DO WHATSAPP ===
let whatsapp = `*${theme.greeting}*\n_${newsletter.intro || "As melhores notícias para você."}_\n\n`;
whatsapp += `*${theme.emoji} SETLIST RÁPIDO*\n`;
whatsapp += whatsappPosts + "\n";
whatsapp += `🔥 *Tem muito mais rolando agora!*\n`;
whatsapp += `Leia as matérias completas, análises e bastidores direto no FreshNews.\n\n`;
whatsapp += `📱 *Abra o App:*\n`;
whatsapp += `👉 https://app.freshnews.com.br/archive/${newsletter.id}\n\n`;
whatsapp += `\`\`\`${theme.footerSignOff}\`\`\``;

// === MONTAGEM DO E-MAIL ===
let html = `
<div style="background-color: ${theme.bg}; padding: 20px 0; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Ubuntu, sans-serif;">
  <div style="background-color: ${theme.cardBg}; margin: 0 auto; padding: 0; max-width: 640px; border: 1px solid rgba(255, 255, 255, 0.1); border-radius: 16px; overflow: hidden;">

    <!-- Header -->
    <div style="padding: 40px 20px; text-align: center; position: relative;">
      <span style="display: inline-block; padding: 4px 12px; border-radius: 12px; font-size: 12px; font-weight: bold; letter-spacing: 2px; margin-bottom: 16px; color: ${theme.color}; background-color: ${theme.color}20;">
        ED. 0${newsletter.edition_number || "X"}
      </span>
      <h1 style="font-size: 36px; font-weight: 900; margin: 0; letter-spacing: -1px; text-transform: uppercase; color: ${theme.color};">
        FRESH NEWS
      </h1>
      <p style="font-size: 11px; margin: 12px 0 0; color: #a0a0a0; letter-spacing: 4px; text-transform: uppercase;">
        ${theme.headerLabel}
      </p>
    </div>

    <!-- Editorial Intro -->
    <div style="padding: 0 40px 30px;">
      <p style="color: ${theme.color}; font-weight: bold; font-size: 16px; margin-bottom: 8px;">
        ${theme.greeting}
      </p>
      <p style="color: #ffffff; font-size: 16px; line-height: 1.6; margin: 0;">
        ${newsletter.intro || "Confira os destaques"}
      </p>
    </div>

    <!-- Divider -->
    <div style="height: 1px; background: linear-gradient(90deg, transparent, ${theme.color}40, transparent); margin: 0 40px 30px;"></div>

    <!-- Posts Dinâmicos -->
    <div style="padding: 0 40px 40px;">
      ${htmlPosts}
    </div>

    <!-- Footer -->
    <div style="background-color: rgba(0,0,0,0.4); padding: 40px; text-align: center; border-top: 1px solid rgba(255, 255, 255, 0.05);">
      <p style="color: #666666; font-size: 12px; margin: 0 0 16px;">
        ${theme.footerSignOff}<br>
        © 2026 Fresh News. Multiverse Edition.
      </p>
      <a href="{{unsubscribe_url}}" style="color: #444444; font-size: 11px; text-decoration: underline;">
        Unsubscribe
      </a>
    </div>
  </div>
</div>
`;

return {
  html_email: html,
  whatsapp_message: whatsapp
};
